import{_ as s,o as e,c as a,ag as i}from"./chunks/framework.OsDJF_Ea.js";const u=JSON.parse('{"title":"Clusters & SSH","description":"","frontmatter":{},"headers":[],"relativePath":"clusters-ssh.md","filePath":"clusters-ssh.md"}'),n={name:"clusters-ssh.md"};function l(o,t,r,h,c,d){return e(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="clusters-ssh" tabindex="-1">Clusters &amp; SSH <a class="header-anchor" href="#clusters-ssh" aria-label="Permalink to &quot;Clusters &amp; SSH&quot;">​</a></h1><p>The <strong>Clusters</strong> panel lists all interactive clusters in your Databricks workspace and lets you SSH into any of them with one click.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li><a href="https://marketplace.visualstudio.com/items?itemName=ms-vscode-remote.remote-ssh" target="_blank" rel="noreferrer">VS Code Remote SSH extension</a></li><li><a href="https://docs.databricks.com/dev-tools/cli/install.html" target="_blank" rel="noreferrer">Databricks CLI</a> ≥ 0.269</li><li>DBR 17+ on the target cluster</li><li>Databricks connection configured in CatalystOps</li></ul><h2 id="connecting-via-ssh" tabindex="-1">Connecting via SSH <a class="header-anchor" href="#connecting-via-ssh" aria-label="Permalink to &quot;Connecting via SSH&quot;">​</a></h2><ol><li>Open the CatalystOps sidebar — find the <strong>Clusters</strong> panel</li><li>Each cluster shows its name, current state (Running, Terminated, Pending, etc.), and Spark version</li><li>Click the <strong>SSH</strong> button next to any cluster</li></ol><p>CatalystOps then:</p><ul><li><strong>If the cluster is stopped</strong> — starts it automatically and polls state every 5 s with live progress</li><li>Runs <code>databricks ssh setup</code> to configure the SSH tunnel keys</li><li>Opens VS Code Remote SSH directly on the cluster driver</li></ul><p>If anything needs fixing first (wrong access mode, Spark version too old), CatalystOps tells you what&#39;s wrong and offers to fix it with a single click — no manual cluster editing required.</p><h2 id="auto-fix-for-ssh-compatibility" tabindex="-1">Auto-Fix for SSH Compatibility <a class="header-anchor" href="#auto-fix-for-ssh-compatibility" aria-label="Permalink to &quot;Auto-Fix for SSH Compatibility&quot;">​</a></h2><p>When <code>databricks ssh setup</code> fails due to an incompatible cluster configuration, CatalystOps offers:</p><ul><li><strong>Set Single User mode</strong> — switches the cluster access mode to Single User (required for SSH)</li><li><strong>Upgrade Spark</strong> — optionally upgrades to Spark 17.3 LTS if the current version is too old</li></ul><p>Both fixes restart the cluster automatically and retry the SSH setup.</p><h2 id="right-click-actions" tabindex="-1">Right-Click Actions <a class="header-anchor" href="#right-click-actions" aria-label="Permalink to &quot;Right-Click Actions&quot;">​</a></h2><p>Right-click any cluster in the panel for additional options:</p><table tabindex="0"><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td><strong>Stop Cluster</strong></td><td>Terminates the cluster</td></tr><tr><td><strong>Reset SSH Host</strong></td><td>Clears the cached SSH alias — forces a fresh <code>databricks ssh setup</code> on next connect</td></tr></tbody></table><h2 id="ssh-tunnel-for-dry-run" tabindex="-1">SSH Tunnel for Dry Run <a class="header-anchor" href="#ssh-tunnel-for-dry-run" aria-label="Permalink to &quot;SSH Tunnel for Dry Run&quot;">​</a></h2><p>You can also route dry-run plan analysis through an SSH tunnel instead of the REST API. This is useful when your cluster is in a private network:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;catalystops.connection.sshTunnel.enabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;catalystops.connection.sshTunnel.connectionName&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;my-cluster&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The <code>connectionName</code> must match the alias set up by <code>databricks ssh setup</code>.</p><h2 id="idle-timeout" tabindex="-1">Idle Timeout <a class="header-anchor" href="#idle-timeout" aria-label="Permalink to &quot;Idle Timeout&quot;">​</a></h2><p>The SSH tunnel closes automatically after a configurable idle period:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;catalystops.ssh.shutdownDelay&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;30m&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div>`,23)])])}const k=s(n,[["render",l]]);export{u as __pageData,k as default};
